theme.headerSearch=function(){function searchOverlay(){let offcanvasSearchTrigger=document.querySelector(".header__actions_btn--search"),offcanvasSidebarSearch=document.getElementById("predictive__search_overlay"),offcanvasSearchClose=document.getElementById("search__close_btn");offcanvasSearchTrigger&&(offcanvasSearchTrigger.addEventListener("click",event=>{event.preventDefault(),offcanvasSidebarSearch.classList.add("active"),document.querySelector("body").classList.add("added__overlay_search"),offcanvasSidebarSearch.addEventListener("transitionend",()=>{offcanvasSidebarSearch.focus(),trapFocus(offcanvasSidebarSearch)},{once:!0})}),offcanvasSidebarSearch.addEventListener("keyup",evt=>{"Escape"===evt.code&&(offcanvasSidebarSearch.classList.remove("active"),document.querySelector("body").classList.remove("added__overlay_search"),removeTrapFocus(offcanvasSearchTrigger))})),offcanvasSearchClose&&offcanvasSearchClose.addEventListener("click",event=>{event.preventDefault(),offcanvasSidebarSearch.classList.remove("active"),document.querySelector("body").classList.remove("added__overlay_search"),removeTrapFocus(offcanvasSearchTrigger)}),document.addEventListener("click",(function(event){let eventTarget=event.target;eventTarget.closest("#predictive__search_overlay")||eventTarget.closest(".header__actions_btn--search")||(offcanvasSidebarSearch.classList.remove("active"),document.querySelector("body").classList.remove("added__overlay_search"))}))}return searchOverlay}();